        ending = self.ending if ending is None else ending
        if ending and not msg.endswith(ending):
            msg += ending
        self._out.write(msg)

# Let's trace what happens
original_flush = sys.stdout.flush
def traced_flush():
    print('sys.stdout.flush called!')
    original_flush()

sys.stdout.flush = traced_flush

